"""
MKT Context Commentary — 1 Chronicles chapter 6
Run: python3 scripts/zc-context-1chronicles-6-6.py

Source data used:
- data/interlinear/1chronicles.json
- data/translation/draft/mediating/1chronicles.json

Key decisions:
- Ch6 is the Levitical chapter: high priestly succession (vv1-15), three Levitical
  genealogies (vv16-30), temple musicians (vv31-48), Aaronic sacrificial role (vv49-53),
  Levitical cities (vv54-81)
- Jehozadak (v15): exile of the high priest is the hinge between monarchy and
  post-exilic priesthood; his son Joshua/Jeshua returns with Zerubbabel (Ezra 2:2; Hag 1:1)
- Samuel's Levitical identity (v27-28): Samuel appears in the Kohathite genealogy,
  resolving the 1 Sam 1:1 'Ephraimite' descriptor as a residential, not tribal, designation
- Heman grandson of Samuel (v33): musical-prophetic tradition connection
- Zadok (v13): founder of the Zadokite priestly line dominant through the Second Temple period
- Levitical cities (vv54-81): fulfillment of Num 35:1-8 and Josh 21
- Asaphite psalms and Ethan's Ps 89 noted at vv39 and v44
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CONTEXT = {
  "6": {
    "1": "<p>1 Chronicles 6 is the Chronicler's fullest treatment of Levi's descendants — the tribe with no territorial allotment (Num 18:20) but uniquely responsible for Israel's worship. The three-clan structure (Gershom, Kohath, Merari) maps directly onto the wilderness organization of Num 3–4, where each clan had specific responsibilities for transporting the tabernacle. The Chronicler reproduces this genealogy in an era when returned exiles needed to verify their Levitical ancestry to resume service (Ezra 2:59-63: priests who could not prove their genealogy were excluded from priestly duties). The chapter moves from the Aaronite priestly succession (vv1-15) to the broader Levitical genealogies (vv16-30) to David's musical appointments (vv31-48) to the distinction between sacrificial and service roles (vv49-53) to the territorial settlement (vv54-81). It is the most comprehensive statement of Levitical organization in the Old Testament.</p>",
    "2": "<p>Kohath is listed first among Levi's sons because the Aaronide priestly line runs through him: Levi → Kohath → Amram → Aaron. The four sons of Kohath (Amram, Izhar, Hebron, Uzziel) are the founders of the four Kohathite sub-clans (Num 3:19; 1 Chr 23:12). In the wilderness these clans were responsible for carrying the most sacred tabernacle objects: the ark, lampstand, table, and altars (Num 4:4-15). Their proximity to the Most Holy Place objects made them both the most privileged and the most endangered Levitical clan — Num 4:20 warns they could not look at the holy things 'even for a moment' lest they die.</p>",
    "3": "<p>The children of Amram are the founding triad of the exodus: Aaron the high priest, Moses the lawgiver, and Miriam the prophetess — identified together in Mic 6:4 as the three leaders through whom YHWH brought Israel out of Egypt. Aaron's four sons follow. Nadab and Abihu died when they offered 'unauthorized fire before the LORD' (Lev 10:1-3, <em>ʾēš zārāh</em>); the entire Aaronic priestly succession therefore runs through Eleazar and Ithamar. The Chronicler includes this information because Aaron's two surviving sons are the ancestors of all legitimate priests; in Solomon's time the two lines were consolidated when Zadok (Eleazar) replaced Abiathar (Ithamar) as sole high priest (1 Kgs 2:26-27).</p>",
    "4": "<p>Eleazar begot Phinehas — a genealogical step with enormous theological weight. Phinehas received from YHWH 'a covenant of perpetual priesthood' (Num 25:10-13) as reward for stopping the Baal-Peor apostasy (Num 25:6-9). This covenant is the OT's strongest guarantee of priestly legitimacy: 'it shall be for him and for his descendants after him the covenant of a perpetual priesthood, because he was jealous for his God and made atonement for the people of Israel.' Every high priest in the Aaronide line is heir to this promise. The post-exilic community valued the Phinehas covenant highly — Ps 106:30-31 and Sir 45:23-26 celebrate him as the paradigmatic defender of YHWH's honor.</p>",
    "5": "<p>Abishua son of Phinehas — the first generation after the Phinehas covenant. Abishua appears in Ezra 7:5 in the ancestry of Ezra the scribe, confirming the Chronicler's list connects to living post-exilic leadership. Josephus (<em>Antiquities</em> 5.11.5) includes Abishua in his priestly succession but provides no narrative detail for his tenure, suggesting the list is genealogical certification rather than historical chronicle for this interval.</p>",
    "6": "<p>Bukki son of Abishua — the high priestly chain continues through the period of the judges. The list here (vv4-9) bridges from the wilderness generation (Eleazar, Phinehas) to the monarchy (Zadok, v13). Because 1 Samuel records two rival priestly families — the Elide priests at Shiloh (from Ithamar) and the Zadokite line (from Eleazar) — the Chronicler's genealogy focuses on the Eleazar-Phinehas succession he regards as legitimate, without commenting on the Elide period.</p>",
    "7": "<p>Uzzi son of Bukki — in Josephus's reconstruction, Uzzi is the high priest during whose tenure the high priesthood passed temporarily to Eli the Ithamarite at Shiloh, in fulfillment of the curse of 1 Sam 2:30-33 on the Elide house. The Chronicler does not address this period of divided priestly leadership; he traces the Eleazar-Phinehas line continuously without acknowledging the Elide interregnum at Shiloh. His silence is theologically motivated: the succession he narrates is the one he regards as unbroken and authoritative.</p>",
    "8": "<p>Zerahiah son of Uzzi — the genealogical list is schematic in this section, covering perhaps four centuries in five names (vv5-9). The compression signals that the Chronicler's purpose is genealogical certification rather than historical chronicle for this interval. The post-exilic community needed to know the Aaronide line was unbroken through the settlement and judges period; biographical detail for each holder was secondary to that certification.</p>",
    "9": "<p>Meraioth son of Zerahiah — the final step before the monarchy period begins to be documented. Three names (vv8-9: Zerahiah, Meraioth) cover the period from the settlement through to the early monarchy, a span during which the Shiloh tabernacle and the Ark's capture (1 Sam 4) created a crisis in Israelite priestly organization. The Chronicler's genealogical silence on this period matches his broader practice of not narrating the northern sanctuary's history.</p>",
    "10": "<p>Azariah is identified not only by his place in the succession but by his active role: 'he served as priest in the temple that Solomon built in Jerusalem.' This is the first verse in the chapter that anchors the priestly line to a specific historical institution. The Solomonic temple (966-586 BCE) becomes the temporal marker for this high priest — the genealogical chain connects the covenant people's founding ancestry to the central institution of the Davidic monarchy. The Chronicler's emphasis on temple service (not only genealogy) reflects his agenda: legitimate priesthood is defined by ancestry <em>and</em> actual service at the designated sanctuary.</p>",
    "11": "<p>Amariah son of Azariah — the succession continues through the monarchy. Several men named Amariah appear in Chronicles (2 Chr 19:11; 31:15), though not all are high priests. The name means 'YHWH has spoken' or 'YHWH has promised,' a theophoric name common in priestly families, reflecting the covenant-speech theology central to Israel's worship community. The repetition of priestly names across generations reflects the practice of naming sons after significant ancestors.</p>",
    "12": "<p>Ahitub son of Amariah — not to be confused with the earlier Ahitub of Eli's family (1 Sam 14:3; 22:9), who was from the Ithamarite line. The Chronicler's Ahitub is in the Eleazar-Zadok succession. The recurrence of names (Ahitub, Amariah, Zadok) within the priestly list reflects the limited onomastic pool of priestly families, where theophoric and ancestral names were commonly recycled across generations to express covenant identity and family continuity.</p>",
    "13": "<p>Zadok son of Ahitub — one of the most historically significant entries in the chapter. Zadok was David's high priest (2 Sam 8:17; 20:25), serving alongside Abiathar during the unified monarchy. When Abiathar supported Adonijah's attempted coup (1 Kgs 1:7), Solomon exiled him and installed Zadok as sole high priest (1 Kgs 2:26-27, 35), fulfilling the curse on Eli's house (1 Sam 2:31-33). From this point the high priesthood remained in the Zadokite family for the entire First Temple period, through the exile, and into the Second Temple. Ezekiel's temple vision reserves the innermost priestly ministry for the 'sons of Zadok' (Ezek 44:15-16). The Qumran community's self-designation as 'sons of Zadok' (1QS 5:2) shows how central this lineage was to Second Temple identity. The Chronicler's placement of Zadok's name anchors the entire priestly succession to the dominant family of the post-exilic era.</p>",
    "14": "<p>Shallum son of Zadok — the step from Zadok to Hilkiah (the high priest who found the law book under Josiah, 2 Kgs 22:8) spans approximately 350 years through a compressed list. The Chronicler counts approximately fifteen high priests from Aaron to the exile — for a 900-year span that averages 60 years per holder, suggesting the list is selective rather than complete. What matters is the unbroken line, not the complete roster.</p>",
    "15": "<p>Jehozadak went into exile when the LORD sent Judah and Jerusalem into exile by the hand of Nebuchadnezzar — the climactic verse of the high priestly succession list. When Nebuchadnezzar destroyed Jerusalem (586 BCE), the high priest himself was carried into exile. This verse is theologically critical for the post-exilic community: it establishes that the Aaronide line was not broken by the exile but carried through it. Jehozadak's son was Joshua/Jeshua the high priest who returned to Jerusalem with Zerubbabel under Cyrus's decree (Ezra 2:2; 3:2; Hag 1:1; Zech 3:1). The exile of the high priest and the return of his son is the genealogical bridge between the pre-exilic and post-exilic worship communities — the temple being rebuilt by the returned community has the same legitimate Aaronide priesthood as the one Nebuchadnezzar destroyed.</p>",
    "16": "<p>The three Levitical clans are re-introduced here (vv16-30) to give their parallel genealogies in full. Verses 1-15 traced the Aaronide priestly line in detail; now the chapter provides the parallel succession lists for Gershom, the broader Kohath (non-Aaronide branches), and Merari. In Num 3–4 these clans had distinct wilderness functions: Gershom carried the tent curtains and screens; Kohath carried the sacred vessels (always covered by the priests before transport); Merari carried the structural frames and pillars. The wilderness roles explain why the three clans are treated as corporate units throughout Levitical legislation — they represent three distinct service ministries, not merely three family groups.</p>",
    "17": "<p>The sons of Gershom — Libni and Shimei — are the founding ancestors of the two Gershomite sub-clans (Num 3:18; 1 Chr 23:7). In the wilderness census of Num 3:21-26 the Gershomites numbered 7,500 males, the second largest Levitical clan. The two sons give their names to the two Gershomite divisions; in David's later reorganization (1 Chr 23:7-11) these clans are assigned as worship assistants under priestly direction. Their naming here as genealogical anchors establishes the family structure that will later be connected to specific temple roles.</p>",
    "18": "<p>The sons of Kohath — Amram, Izhar, Hebron, and Uzziel — repeat v2 (already listed in the Aaronide succession). Here the four Kohathite sub-clans appear to show the broader Kohathite family beyond Aaron's line. Izhar's most famous descendant is Korah (Num 16:1), whose rebellion against Moses ended in divine judgment; yet Korah's sons survived (Num 26:11) and became temple singers (Ps 42-49; 84-85; 87-88 are 'of the Sons of Korah'). Uzziel's grandson Mishael helped carry Nadab and Abihu's bodies from the sanctuary (Lev 10:4).</p>",
    "19": "<p>The sons of Merari — Mahli and Mushi — are the founding ancestors of the two Merarite sub-clans (Num 3:20; 1 Chr 23:21). In the wilderness census the Merarites numbered 6,200 males, the smallest clan, but they transported the heaviest tabernacle components: the frames, bars, pillars, and bases — requiring four wagons and eight oxen (Num 7:8). The Chronicler's list establishes their place alongside the other clans without narrative elaboration; their role is organizational certification.</p>",
    "20": "<p>Gershom's extended line: Libni his son, Jahath his son, Zimmah his son. The Chronicler traces the Gershomite succession through multiple generations to connect the founding ancestor to the temple musicians of vv31-48. Several names in the Gershomite list appear later in Chronicles' narrative sections: Zimmah and Joah appear in 2 Chr 29:12 among the Gershomites who participated in Hezekiah's temple purification, demonstrating that the genealogical lines in ch6 map onto real institutional continuity.</p>",
    "21": "<p>Joah son of Zimmah, Iddo his son, Zerah his son, Jeatherai his son — the Gershomite succession continues. The name Iddo ('adorned' or 'timely') is a common name in Chronicles; Iddo the prophet is cited as a source document (2 Chr 9:29; 12:15; 13:22), though the connection to this Gershomite Iddo is uncertain. The list spans from the wilderness through the monarchy period in compressed form, each name serving as a documented generational link.</p>",
    "22": "<p>The sons of Kohath: Amminadab his son, Korah his son, Assir his son — this branch of the Kohathite line leads to Korah the rebel (Num 16). The listing of the Korahite succession without comment on the rebellion reflects the Chronicler's practice of including families in their proper genealogical place regardless of their narrative history. Korah's sons survived (Num 26:11: 'the sons of Korah did not die') and their descendants served as temple singers and gatekeepers — the Korahite guilds are well attested in the Psalter and in Chronicles' cultic records.</p>",
    "23": "<p>Elkanah his son, Ebiasaph his son, Assir his son — the Korahite succession continues. Ebiasaph (= Abiasaph in Exod 6:24) is listed as a son of Korah who survived the judgment, making him an ancestor of the post-rebellion Korahite community. The Chronicler traces this line because it leads ultimately to the temple musicians and gatekeepers (1 Chr 9:19; 26:1) whose service in the Second Temple depended on documented Korahite ancestry.</p>",
    "24": "<p>Tahath his son, Uriel his son, Uzziah his son, and Shaul his son — further Kohathite succession bridging the wilderness to the settlement period. Uriel appears in 1 Chr 15:5, 11 as a Kohathite leader appointed by David for the ark-bringing procession, connecting the genealogical list directly to a Davidic narrative event. These otherwise undocumented names serve as generational links certified by the Chronicler's genealogical tradition.</p>",
    "25": "<p>The sons of Elkanah: Amasai and Ahimoth — a branch-point in the Kohathite tree. From this Elkanah the line divides into two branches. The name Elkanah ('God has purchased/possessed') is common in Levitical families; multiple Elkanahs appear in the Kohathite succession, reflecting the practice of naming sons after grandfathers. This Elkanah is ancestral to the Asaphite and related musical guilds in the broader Kohathite network.</p>",
    "26": "<p>Elkanah — his son was Zophai, his son Nahath — the genealogical line approaches the famous Elkanah who is Samuel's father (v27-28). The Chronicler traces this branch through successive Elkanahs, creating apparent repetition in the list that reflects the family's naming conventions. The reader familiar with 1 Samuel 1 would recognize the names converging toward Samuel's birth narrative.</p>",
    "27": "<p>Eliab his son, Jeroham his son, Elkanah his son — this Elkanah is Samuel's father. First Samuel 1:1 calls him 'an Ephraimite from Ramathaim-zophim in the hill country of Ephraim,' which appears to contradict a Levitical identity. The Chronicler's genealogy resolves this: 'Ephraimite' in 1 Sam 1:1 is a residential designation (his family lived in Ephraim's territory), not a tribal identifier. The Levitical families resided in the 48 Levitical cities distributed across all tribal territories; a Kohathite Levite living in Ephraim's hill country would naturally be called an 'Ephraimite' by his neighbors without claiming Ephraimite tribal descent. This reading makes Samuel's priestly behavior in 1 Samuel (offering sacrifice, serving at the sanctuary, anointing kings) consistent with his genealogical identity as a Kohathite Levite.</p>",
    "28": "<p>The sons of Samuel: Joel the firstborn, and Abiah the second — the Chronicler connects Samuel's sons to the genealogical list. These are the Joel and Abiah whose misconduct as judges prompted the elders to request a king (1 Sam 8:1-5: 'his sons did not follow his ways but turned aside after gain and accepted bribes'). The naming of Samuel's sons here creates an ironic connection to vv31-48: Samuel's corrupt son Joel fathered Heman (v33), who became one of the three directors of Israel's temple worship. Covenant failure and covenant continuity are woven into the same family tree; YHWH's purposes are not frustrated by the moral failures of intermediate generations.</p>",
    "29": "<p>The sons of Merari: Mahli, Libni his son, Shimei his son, Uzzah his son — the Merarite succession. Uzzah appears later in 1 Chr 13:9-10, where a different Uzzah (possibly a descendant or namesake) dies after touching the ark when the oxen stumbled during its transport to Jerusalem. The incident illustrates that proximity to the sacred objects carried by Merari's descendants was dangerous without prescribed protocols — even well-intentioned action outside the divine order was judged. The Chronicler includes the genealogical Uzzah without editorial comment, preserving the family connection that his narrative readers would recognize.</p>",
    "30": "<p>Shimea his son, Haggiah his son, Asaiah his son — the Merarite succession ends here. Asaiah appears in 1 Chr 15:6, 11 as a Merarite leader appointed by David for the ark-bringing procession, directly connecting this genealogical line to a specific historical event in the Davidic narrative. The Chronicler's habit of linking genealogical names to later narrative events (Uriel v24; Asaiah v30) demonstrates that his genealogical chapters are not isolated lists but are integrated with the book's narrative sections.</p>",
    "31": "<p>'These are the men David appointed over the service of song in the house of the LORD, after the ark had found its resting place.' This verse is the chapter's theological hinge: from genealogy to institution. David's appointment of professional singers marks a significant development in Israelite worship. The phrase 'after the ark had found its resting place' connects the musical appointment to the establishment of a permanent cult center (1 Chr 15-16) — worship organization follows the settlement of divine presence. The Chronicler presents David as the founding architect of temple worship, as significant as Solomon the temple's builder; the musical guilds are David's institutional gift to the temple that outlasted him by centuries.</p>",
    "32": "<p>'They ministered with song before the tabernacle of the tent of meeting until Solomon built the house of the LORD in Jerusalem, and they served according to their prescribed order (<em>mišpāṭām</em>).' The singers served at both David's tabernacle-tent in Jerusalem (where the ark was housed, 2 Sam 6:17; 1 Chr 15:1; 16:1) and later in Solomon's temple. The term <em>mišpāṭām</em> (their prescribed order, ordinance) signals that this is not informal or spontaneous worship but institutionally structured liturgy with fixed roles, sequences, and personnel. Second Temple Judaism inherited this structured musical liturgy; the Psalter's five-book organization may reflect the liturgical collections established by David's three musical directors.</p>",
    "33": "<p>Heman the singer, son of Joel, son of Samuel the prophet — one of the most revealing genealogical connections in Chronicles. The premier temple musician was Samuel's grandson. Heman was the first of three directors David appointed over temple music (alongside Asaph and Ethan, vv39, 44). His ancestry from Samuel through Joel establishes that the prophetic and musical-liturgical traditions are not separate streams but family-linked: Samuel's grandson expressed in temple music the same YHWH-devotion that Samuel expressed in prophecy and covenant administration. Psalm 88 is headed 'A Maskil of Heman the Ezrahite,' likely composed by this Heman or his guild — a psalm of profound individual lament that ends without resolution ('darkness is my closest friend'), demonstrating that Israel's court music was not limited to triumphant praise.</p>",
    "34": "<p>The son of Joel, the son of Elkanah — Heman's ancestry runs through Joel (Samuel's corrupt son) and Elkanah (Samuel's faithful father). The chain Elkanah → Samuel → Joel → Heman is the genealogical spine of the Kohathite musical tradition — the prophetic family of Ramah became the musical family of Jerusalem's temple. The irony that the corrupt Joel (1 Sam 8:3) fathered the great Heman is not commented upon; the Chronicler presents the genealogy as a given, allowing readers to draw their own connections.</p>",
    "35": "<p>The son of Mahath, the son of Amasai — tracing Heman's ancestry back through the Kohathite line to Amasai (listed in v25 as a son of Elkanah). The extended genealogy for Heman (vv33-38) is the most detailed ancestry trace in the chapter, reflecting his prominence as the first-named and presumably lead temple musician. The care given to his genealogy certifies not only his personal credentials but the Kohathite music tradition's Levitical legitimacy.</p>",
    "36": "<p>The son of Elkanah, the son of Joel — the repeated Elkanah/Joel names reflect the naming conventions of Levitical families, where names were recycled across generations. This Elkanah and Joel are earlier ancestors, not the Samuel-era Elkanah and Joel; the Chronicler traces the line back through multiple generations of the same names to reach the founding Kohathite genealogy. The musical guilds' legitimacy rested on documented ancestry from David's appointees back through Levi via Kohath.</p>",
    "37": "<p>The son of Azariah, the son of Zephaniah — approaching the earlier Kohathite generations. Zephaniah ('YHWH has treasured/hidden') is a theophoric name common in priestly and Levitical contexts; a different Zephaniah son of Maaseiah was a priestly official in Jeremiah's time (Jer 29:25-29), though not the same person. The variety of theophoric names in the Levitical genealogies (YHWH-element names predominate) reflects the naming practice of families embedded in the worship institutions of Israel.</p>",
    "38": "<p>The son of Tahath, the son of Assir, the son of Ebiasaph, the son of Korah — Heman's ancestry is now traced back to Korah the rebel of Num 16. The Chronicler makes no comment on the rebellion; the genealogy simply passes through Korah's name as a generational link. This is significant: the post-exilic temple community did not suppress the Korahite guilds despite their ancestor's infamy. Numbers 26:11 established that 'the sons of Korah did not die,' and their musical guilds continued in temple service for centuries. The Psalter's Korahite psalms (Ps 42-49; 84-85; 87-88) are the surviving evidence of their ongoing liturgical contribution.</p>",
    "39": "<p>Asaph, who stood at his right hand — David's second temple music director, standing at Heman's right in the liturgical arrangement. Asaph's prominence in the Psalter is remarkable: twelve psalms bear his name (Ps 50 and Ps 73-83), more than any name except David. The Asaphite psalms are notable for their communal lament and historical retrospection — they deploy Israel's history as theological argument about YHWH's justice (Ps 73), faithfulness (Ps 78), and judgment (Ps 79-80). The Asaphite guild was still functioning at Nehemiah's wall dedication centuries later (Neh 12:35, 46), confirming their institutional continuity from David through the Second Temple period. Asaph's genealogy (vv40-43) shows he was a Gershomite, not a Kohathite like Heman — the three music directors represent all three Levitical clans.</p>",
    "40": "<p>The son of Michael, the son of Baaseiah — Asaph's ancestry traces back through a different Levitical branch from Heman's Kohathite line. Asaph is a Gershomite (vv40-43), which means David's three temple music directors represent all three Levitical clans: Heman from Kohath, Asaph from Gershom, and Ethan from Merari (v44). David's musical organization thus mirrors the tripartite Levitical structure of Num 3–4 in which each clan contributed a distinct service ministry — the musical arrangement is a worship-institutional expression of the same balanced structure.</p>",
    "41": "<p>The son of Malchijah, the son of Ethni, the son of Zerah — continuing Asaph's Gershomite genealogy. Zerah was one of Judah's twin sons by Tamar (Gen 38:30; 1 Chr 2:4), which might seem to place Asaph in Judah rather than Levi. However, the name Zerah ('shining/rising of light') is common across multiple tribes; this Zerah is in the Gershomite line. The Chronicler's genealogy does not conflate tribal identities even when names overlap.</p>",
    "42": "<p>The son of Adaiah, the son of Ethan, the son of Zimmah — the Gershomite ancestry approaches the wilderness generation. Zimmah appeared earlier in v20 as a step in the Gershomite succession, confirming that Asaph's ancestry runs through the same Gershomite family tree that the chapter has already traced in general outline. The repetition of Zimmah in two contexts (v20 and v42) reflects the Chronicler's interlocking genealogical method.</p>",
    "43": "<p>The son of Shimei, the son of Jahath, the son of Gershom, the son of Levi — Asaph's ancestry is traced all the way to Gershom, Levi's son. The connection Gershom → Levi anchors Asaph in the founding generation of the Levitical tribe. For the post-exilic community, this genealogical depth was not pedantry: it answered the anxious question of who was qualified to lead temple worship (cf. Ezra 2:59-63). Asaph's line is certified back to the foundation, and no challenger could question his credentials.</p>",
    "44": "<p>Ethan the son of Kishi, from the sons of Merari, stood at the left hand — the third temple music director, representing the Merarite clan. The Merarites transported the tabernacle's structural components in the wilderness; now their descendant carries the musical ministry's left wing in the temple. Psalm 89 is titled 'A Maskil of Ethan the Ezrahite.' Whether this Merarite Ethan and the 'Ethan the Ezrahite' mentioned in 1 Kgs 4:31 as a proverbially wise man are identical is disputed. If they are, Ps 89 — which wrestles with the apparent collapse of the Davidic covenant promise after Babylon's destruction of Jerusalem — comes from the founding director of Merari's choir, whose lament was sung by his descendants as they rebuilt the temple without a Davidic king on the throne.</p>",
    "45": "<p>The son of Hashabiah, the son of Amaziah, the son of Hilkiah — Ethan's Merarite ancestry. These names do not appear in prominent narrative contexts elsewhere; their function is to provide the certified chain linking Ethan to his Merarite Levitical identity. Hilkiah ('YHWH is my portion') is a significant priestly name — the high priest Hilkiah who discovered the law book under Josiah (2 Kgs 22:8; 2 Chr 34:9) is a Zadokite Hilkiah, not this Merarite one; the name's frequency in priestly circles reflects its theological resonance.</p>",
    "46": "<p>The son of Amzi, the son of Bani, the son of Shemer — the Merarite ancestry continues through names that appear only in genealogical lists. Shemer ('watchman' or 'preserved one') appears in a completely different context in 1 Kgs 16:24 as the owner of the hill that Omri purchased and built Samaria on — that Shemer is from Ephraim; this Merarite Shemer is unrelated. The overlap of names across tribes reflects the common onomastic pool of the Hebrew-speaking communities of the first millennium BCE.</p>",
    "47": "<p>The son of Mahli, the son of Mushi, the son of Merari, the son of Levi — Ethan's ancestry traced back to Merari and Levi, completing his genealogical certification. The Merari → Levi connection parallels the Gershom → Levi connection for Asaph (v43) and the Korah → Kohath → Levi connection for Heman (v38). All three music directors are certified Levites with ancestry traceable to Levi's three sons, and together they represent the complete Levitical community in worship.</p>",
    "48": "<p>'Their kinsmen the Levites were appointed for all the service of the tabernacle, the house of God' — the three named directors had colleagues serving in every other Levitical function. The tabernacle and temple required dozens of roles beyond music: gatekeepers, treasurers, bakers of the showbread, preparers of the anointing oil and incense. Second Temple texts, particularly 1QS and 4QMMT from the Dead Sea Scrolls, document the elaborate liturgical schedules that defined these roles in the post-exilic period. The Chronicler's notice of 'all the service' makes clear that the temple's operation was a complex institution requiring extensive personnel, not simply a single priestly family running a shrine.</p>",
    "49": "<p>'But Aaron and his sons were responsible for the altar of burnt offering and the altar of incense, for all the service of the Most Holy Place, and for making atonement for Israel — exactly as Moses the servant of God had commanded.' This verse draws the hard line between Aaronide priests and the broader Levitical service personnel. Only Aaron's sons could offer sacrifice (Num 3:10; 18:7 — 'the outsider who comes near shall be put to death'). The distinction was socially and politically significant in the post-exilic community where priestly families competed for status and resources. The phrase 'exactly as Moses the servant of God commanded' invokes Pentateuchal authority to ratify the Aaronic monopoly on sacrificial service — this is not the Chronicler's innovation but Mosaic legislation. Ezra's community enforced this distinction rigorously (cf. Neh 13:28-30).</p>",
    "50": "<p>The sons of Aaron — Eleazar his son, Phinehas his son, Abishua his son — a brief recapitulation of the Aaronide succession already given in vv4-15. The repetition emphasizes the connection between the Aaronic sacrificial role (v49) and the Aaronic genealogy: the authority to offer sacrifice belongs to this specific family certified by this specific ancestry. The doubling of the list follows the Chronicler's standard technique of restating key genealogical data when introducing a new institutional function (first the genealogy, then the function, then a compressed re-statement confirming the link).</p>",
    "51": "<p>Bukki his son, Uzzi his son, Zerahiah his son — the recapitulated succession continues from the founding generation (Aaron → Eleazar → Phinehas) through the wilderness and settlement. These names appear only in the genealogical record; they are documented links rather than narrative actors. Their inclusion in both the full list (vv4-9) and the recapitulation confirms their place in the certified chain.</p>",
    "52": "<p>Meraioth his son, Amariah his son, Ahitub his son — the compressed recapitulation approaches the monarchy period. Three names here cover the same period as Judges and early Samuel, during which the priestly history was dominated by the Elide family at Shiloh. The Chronicler's silence on Eli and Shiloh is characteristic: he focuses on the line he regards as legitimate rather than acknowledging rival priestly traditions.</p>",
    "53": "<p>Zadok his son, Ahimaaz his son — the recapitulation ends at the monarchy's beginning: Zadok the high priest under David and Solomon, and his son Ahimaaz who ran to David with news of Absalom's defeat (2 Sam 18:19-29). The list ends at Ahimaaz rather than continuing through the later monarchy because the Chronicler's structural purpose is to connect the founding Aaronide line to the Davidic monarchy's establishment. From this genealogical anchor, post-exilic Zadokite high priests (including Joshua son of Jehozadak, v15) claim their unbroken legitimacy.</p>",
    "54": "<p>'These are their dwelling places according to their allotted territories' — the chapter's final section (vv54-81) lists the 48 Levitical cities distributed across Israel's tribal territories, implementing Num 35:1-8 (Moses' command that Israel give Levites 48 cities with pasturelands) and Josh 21 (its execution under Joshua and Eleazar). The Chronicler reproduces the list in summary form to document that Mosaic legislation was fulfilled in the settlement. For the post-exilic community this list had practical significance: the Levitical cities defined the territorial network of worship personnel and informed which families had historical claims to specific towns. The distribution proceeds by lot (<em>gôrāl</em>), emphasizing divine sovereignty over territorial allocation consistent with Num 33:54.</p>",
    "55": "<p>They gave them Hebron in the land of Judah with its surrounding pasturelands — Hebron is the most historically resonant of the Aaronide cities. It was Abraham's burial place (Gen 23), David's first capital (2 Sam 2:11), and the site where David was anointed king over all Israel (2 Sam 5:3; 1 Chr 11:3). Its assignment to Aaron's descendants (the Kohathite priestly family) layers sacred history onto a sacred space: the same city that witnessed the Abrahamic covenant burial and the Davidic covenant coronation becomes a center of Aaronide priestly residence.</p>",
    "56": "<p>'But the fields of the city and its villages they gave to Caleb son of Jephunneh' — Hebron's agricultural land remained with Caleb, who received it as his personal inheritance because of his faithfulness during the spy mission (Num 13:30; 14:24; Josh 14:13-14). The Levites received the city itself and its pastureland ring for their animals (Num 35:2-5) but not the farmland. This arrangement reflects the Levites' unique economic position: they resided in cities across Israel's territory but supported themselves through tithes and offerings rather than farming (Num 18:21-24). Caleb's agricultural possession around Levitical Hebron illustrates the coexistence of tribal and Levitical land rights in the same location.</p>",
    "57": "<p>The sons of Aaron received the cities of refuge: Hebron, Libnah, Jattir, Eshtemoa — four of the six cities of refuge (Num 35:6, 11-15; Josh 20) were assigned to the Aaronide family. The cities of refuge were Levitical cities where an unintentional manslayer could flee from the blood-avenger until standing trial. Their assignment to Aaron's sons is structurally coherent: the manslayer remained in the city of refuge 'until the death of the high priest' (Num 35:25), after which he could return home. The intersection of Aaronic priesthood and civil justice embedded in these cities shows that the Levitical city network served judicial-civil functions alongside the worship function — it was an institutional infrastructure spanning sanctuary, law, and community order.</p>",
    "58": "<p>Hilen with its pasturelands, Debir with its pasturelands — two additional Kohathite cities in Judah (Josh 21:15). The pastureland (<em>migrāš</em>, from <em>gāraš</em> = to drive out) designation is specified for each city — it is the zone extending 1,000 cubits beyond the city wall reserved for Levitical animals, following Num 35:4-5 which specifies precise measurements. The legal precision reflects the care given to Levitical land rights: they had defined, documented, protected grazing access, not merely informal arrangement.</p>",
    "59": "<p>Ashan with its pasturelands and Beth-shemesh with its pasturelands — two more Kohathite cities in the Shephelah region west of Judah. Beth-shemesh ('house of the sun') was on the Philistine border — the first Israelite town where the returned ark was received after its Philistine sojourn (1 Sam 6:9-12). Its assignment to the Levites placed worship personnel at a culturally and historically charged border location, the very site that had received the returning ark of the covenant.</p>",
    "60": "<p>From the tribe of Benjamin: Gibeon, Geba, Allemeth, and Anathoth — four Aaronide cities in Benjamin. Anathoth is notable on multiple levels: Solomon exiled the priest Abiathar to Anathoth (1 Kgs 2:26), and it was the birthplace of Jeremiah the prophet (Jer 1:1; 11:21). Jeremiah's priestly connections are explained by this Levitical city assignment — his family were Aaronide priests in a Levitical city in Benjamin's territory. Together the Aaronide cities from Judah, Simeon, and Benjamin (thirteen total) formed a priestly corridor through the southern tribes closest to Jerusalem.</p>",
    "61": "<p>The rest of the Kohathite families received ten cities by lot from the half-tribe of Manasseh — these are the non-Aaronide Kohathites (the broader Kohathite clan beyond Aaron's sons). The Aaronide priests received cities in the southern territories near Jerusalem; the broader Kohathite family received cities in western Manasseh in the central hill country. This geographic distribution placed different branches of the Kohathite clan in distinct regions, extending the network of Levitical presence northward and westward from the priestly core in Judah and Benjamin.</p>",
    "62": "<p>The Gershomites received thirteen cities from the tribes of Issachar, Asher, Naphtali, and the half-tribe of Manasseh in Bashan — all northern territories. The Gershomite distribution in the north reflects a geographic logic to the overall allocation: the Levites were distributed across the entire territory, not concentrated in any single region. The northern Gershomite cities served as worship and instruction centers for the northern tribes, consistent with the Levitical role of teaching the law described in 2 Chr 17:7-9 (Jehoshaphat's Levitical teachers sent throughout Judah) — a role that presumably characterized the Gershomites in Israel's northern territories as well.</p>",
    "63": "<p>The Merarites received twelve cities from Reuben, Gad, and Zebulun — across both Transjordan and the Galilean north. The Transjordanian Merarite cities served the tribes east of the Jordan who were geographically distant from Jerusalem but fully part of the covenant community. The distribution of Levites throughout Transjordan reflects the Mosaic inclusion of Reuben, Gad, and half-Manasseh in the covenant territorial structure (Num 32) — YHWH's worship infrastructure extended to the eastern margins of Israel's land.</p>",
    "64": "<p>The Israelites gave the Levites these cities with their pasturelands — the summary formula confirms that the 48-city distribution was a collective action by all Israel, not the assignment of a single tribe or leader. The formula 'the Israelites gave' (<em>wayyitᵉnû bᵉnê Yiśrāʾēl</em>) echoes Josh 21:3 and frames the Levitical city system as a pan-Israelite covenant obligation. For the Chronicler, writing to a post-exilic community that needed to rebuild its support structures for temple personnel, this communal provision model had programmatic force: the entire community bore responsibility for the material support of its worship leaders.</p>",
    "65": "<p>They designated by lot from the tribe of Judah, from the tribe of Simeon, and from the tribe of Benjamin those cities that are mentioned by name — the lot (<em>gôrāl</em>) mechanism appears explicitly. The lot removes human preference and political calculation from the territorial process; allocation goes where divine guidance directs. This same lot mechanism governs tribal allotments throughout Numbers and Joshua, and it appears at the cross (John 19:24, soldiers casting lots for Jesus' garments, echoing Ps 22:18) and at the selection of Matthias (Acts 1:26). The theological consistency of the lot as an instrument of divine direction across these contexts reflects a unified OT-NT understanding of how YHWH guides contingent human decisions.</p>",
    "66": "<p>Some of the Kohathite families received cities from the territory of the tribe of Ephraim — the non-Aaronide Kohathites in Ephraim's territory. Ephraim contained Shiloh, the site of the pre-Davidic tabernacle (Josh 18:1; 1 Sam 1:3), and Shechem, the great covenant assembly site (Josh 24). Having Kohathite Levites in Ephraim meant that the tribal territory with the most important non-Jerusalemite worship history also had resident Levitical personnel — the Kohathite presence in Ephraim linked the Shiloh tradition to the broader Levitical institutional framework.</p>",
    "67": "<p>They gave them the cities of refuge: Shechem in the hill country of Ephraim with its pasturelands, and Gezer with its pasturelands — Shechem as a city of refuge appears in Josh 20:7; 21:21. Shechem was the most theologically layered city in Ephraim: the site of Abram's first altar in Canaan (Gen 12:6-7), the burial place of Joseph's bones (Josh 24:32), the venue for Joshua's covenant renewal assembly (Josh 24:1-28), and the place where the northern tribes broke from Rehoboam (1 Kgs 12:1). Its status as both a city of refuge and a Kohathite Levitical city concentrates multiple layers of covenant history in a single location.</p>",
    "68": "<p>Jokmeam with its pasturelands, Beth-horon with its pasturelands — Beth-horon (the upper and lower passes) was a strategically critical military route connecting the coastal plain to the central hill country and Jerusalem. It was the site of Joshua's victory over the five Amorite kings (Josh 10:10-11, the battle of the long day) and later of Maccabean victories against Seleucid forces (1 Macc 3:13-25; 7:39-50). The assignment of Beth-horon to Kohathite Levites placed worship personnel at a militarily and commercially significant chokepoint — reinforcing that Levitical cities served multiple community functions beyond religious ceremony.</p>",
    "69": "<p>Aijalon with its pasturelands and Gath-rimmon with its pasturelands — two Kohathite cities from Dan's original allotment. Aijalon is the valley where Joshua commanded the sun and moon to stand still during the battle against the Amorite coalition (Josh 10:12-13: 'Sun, stand still at Gibeon, and moon, in the Valley of Aijalon'). The miracle site becomes a Levitical city without comment; the Chronicler lists it as geography, not prodigy. Its presence in the Levitical city network documents the geographic reach of the Kohathite community across the Shephelah.</p>",
    "70": "<p>From the half-tribe of Manasseh: Aner with its pasturelands and Bileam with its pasturelands — Kohathite cities in western Manasseh. The city names here differ slightly from Josh 21:25 (Taanach and Gath-rimmon), which may reflect textual transmission variation or city-name changes over the centuries between Joshua's list and the Chronicler's reproduction. Minor variation between parallel lists is characteristic of the Chronicler's relationship to his source material in Samuel-Kings; the same pattern appears here with the Joshuanic list.</p>",
    "71": "<p>To the Gershomites: from the half-tribe of Manasseh, Golan in Bashan with its pasturelands and Ashtaroth with its pasturelands — Golan is a city of refuge (Josh 20:8) in the region now called the Golan Heights. Ashtaroth was the capital of Og king of Bashan (Deut 1:4; Josh 9:10), whose defeat by Moses opened Transjordan. Giving former Canaanite royal capitals to Gershomite Levites reflects the theological claim of conquest: YHWH's victory transformed pagan cult centers into stations of Israel's worship infrastructure. The name Ashtaroth recalls the Canaanite goddess Ashtoreth; its conversion to a Levitical city is an implicit polemic against the religion it once centered.</p>",
    "72": "<p>From the tribe of Issachar: Kedesh with its pasturelands, Daberath with its pasturelands — Gershomite cities in the Jezreel Valley. These placed Levites in the broad agricultural plains of lower Galilee, ensuring that the major grain-producing regions of Israel had resident Levitical instructors and worship leaders. The Jezreel Valley's cities appear repeatedly in OT narratives as locations of military and political significance (Megiddo, Jezreel, Shunem); their Levitical city status embedded Israel's worship network in its most strategically contested territory.</p>",
    "73": "<p>Ramoth with its pasturelands and Anem with its pasturelands — additional Gershomite cities in Issachar's territory. The allocation of multiple Levitical cities to Issachar reflects the tribe's economic significance (Gen 49:14-15 emphasizes Issachar's settled agricultural life). More populated agricultural territory meant more need for Levitical service personnel to staff the worship, judicial, and instructional functions that the Levitical city network was designed to provide.</p>",
    "74": "<p>From the tribe of Asher: Mashal with its pasturelands, Abdon with its pasturelands — Gershomite cities in Asher's coastal territory, the Mediterranean littoral north of Mount Carmel. Asher's territory included some of the most fertile land in Canaan (Gen 49:20: 'Asher's food shall be rich, and he shall yield royal delicacies'). Levitical cities in Asher served prosperous coastal settlements that, given their proximity to Phoenicia, were culturally exposed to Baal and Asherah worship (the same pressures that made Jezebel's influence so destructive in the Omride period).</p>",
    "75": "<p>Hukok with its pasturelands and Rehob with its pasturelands — two more Gershomite cities in Asher. The distribution of Levitical cities throughout Asher placed worship infrastructure in one of Israel's most exposed territories — the region that bordered Phoenicia and was culturally permeable to its religious influence. In times of syncretism (as under the Omrides whose royal house was Phoenician), Levitical presence in Asher may have served as an institutional counterweight to the Baal-Asherah cult network that Elijah confronted at Carmel.</p>",
    "76": "<p>From the tribe of Naphtali: Kedesh in Galilee with its pasturelands, Hammoth-dor with its pasturelands, and Kartan with its pasturelands — Gershomite cities in Naphtali's territory in upper Galilee. Kedesh in Galilee was a city of refuge (Josh 20:7; 21:32), the home of Barak son of Abinoam (Judg 4:6), and later a site of Tiglath-pileser III's deportation of the Galilean population (2 Kgs 15:29). Isaiah's prophecy of a 'great light' arising in 'Galilee of the nations' (Isa 9:1-2), in the territory of Zebulun and Naphtali — fulfilled in Jesus' Galilean ministry (Matt 4:13-16) — covered exactly the region where these Naphtali Levitical cities stood.</p>",
    "77": "<p>To the Merarites: from the tribe of Zebulun, Rimmono with its pasturelands and Tabor with its pasturelands — Merarite cities in Zebulun's territory. Mount Tabor, assigned to Levitical pasturelands, is one of the most prominent landmarks in lower Galilee. It was the assembly point for Deborah and Barak's forces before the battle against Sisera (Judg 4:6-14) and is the traditional site of the Transfiguration of Jesus (Matt 17:1-8; Luke 9:28-36), where Moses and Elijah appeared alongside him in conversation. A mountain already associated with covenant assembly and prophetic encounter in the OT tradition becomes in the NT the site of the climactic prophetic-lawgiver encounter with the Son of God.</p>",
    "78": "<p>From across the Jordan at Jericho, on the east side of the Jordan, from the tribe of Reuben: Bezer in the desert with its pasturelands, Jahzah with its pasturelands — the Transjordanian Merarite cities begin with Reuben's territory. Bezer is a city of refuge (Josh 20:8), one of three Transjordanian cities of refuge alongside Ramoth-gilead and Golan, providing judicial asylum in the eastern regions. The geographic marker 'from across the Jordan at Jericho' reflects the Chronicler's Jerusalem-centered perspective, viewing Transjordan as across the river from the land's cultic center.</p>",
    "79": "<p>Kedemoth with its pasturelands and Mephaath with its pasturelands — Merarite cities further into Reuben's Transjordanian territory. Kedemoth appears in Deut 2:26 as the place from which Moses sent messengers to Sihon king of Heshbon requesting peaceful passage before the conquest. Its Levitical assignment anchors a site associated with the initial diplomatic encounter of the Transjordanian campaign within the post-conquest institutional structure — the geography of Israel's history is redeemed into the geography of Israel's worship network.</p>",
    "80": "<p>From the tribe of Gad: Ramoth in Gilead with its pasturelands, Mahanaim with its pasturelands — Merarite cities in Gad's Gilead territory. Ramoth-gilead was a city of refuge (Josh 20:8) and a militarily critical city — the site of Ahab's fatal battle against the Arameans (1 Kgs 22:3-38) and of Jehu's anointing as king (2 Kgs 9:1-6). Mahanaim ('two camps') was where the angels met Jacob (Gen 32:1-2) and where David fled during Absalom's revolt (2 Sam 17:24). Cities carrying this weight of patriarchal, prophetic, and royal history are assigned to Merarite Levites — worship infrastructure embedded in the most historically resonant sites of Israel's narrative.</p>",
    "81": "<p>Heshbon with its pasturelands and Jazer with its pasturelands — the final two Merarite cities, in Gad's southern Transjordanian territory. Heshbon was the capital of Sihon king of the Amorites (Num 21:25-26; Deut 2:24-26) whose defeat by Moses opened the Transjordan conquest. Jazer is mentioned in Num 21:32 as an Amorite city taken by Moses' scouts before the main campaign. Both were former Amorite strongholds that Israel's conquest transformed into stations of YHWH's worship network. The chapter ends on Transjordanian soil, having traced the Levitical community from its ancestral roots (Levi's three sons) through its genealogical development, musical institutions, priestly roles, and geographic deployment across Israel's entire territory — the most comprehensive portrait of Levitical organization in the biblical corpus.</p>"
  }
}

def main():
    c = load_comm('mkt-context', '1chronicles')
    merge_comm(c, CONTEXT)
    save_comm('mkt-context', '1chronicles', c)
    count = sum(len(v) for v in CONTEXT.values())
    print(f'1chronicles mkt-context ch6: wrote {count} verses')

if __name__ == '__main__':
    main()
